function ConfirmSubjectInfo({ PI, A, G, M, S, T, EG, setCleared, setDisplayImage, setwavePlayer_url, setshowed_text, Fileidx, setshowed_pinyin}){
  const allFilled = [PI, A, G, M, S, T, EG].every(v => v && v.trim() !== '')
